# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from headers like 'X-Enrich-URL', 'X-Enrich-URL-1', 'X-Enrich-URL-2', etc.
    Fetches data from those URLs and adds the responses as new headers
    before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Collect all enrichment URLs from headers
    enrich_urls = []
    
    # Check for primary X-Enrich-URL header
    if 'x-enrich-url' in headers:
        for header_entry in headers['x-enrich-url']:
            url = header_entry.get('value', '').strip()
            if url:
                enrich_urls.append(url)
    
    # Check for numbered enrichment URL headers (x-enrich-url-1, x-enrich-url-2, etc.)
    for i in range(1, 11):  # Support up to 10 additional enrichment URLs
        header_key = f'x-enrich-url-{i}'
        if header_key in headers:
            for header_entry in headers[header_key]:
                url = header_entry.get('value', '').strip()
                if url:
                    enrich_urls.append(url)
    
    # If no enrichment URLs found, pass through the request unchanged
    if not enrich_urls:
        return request
    
    enrichment_results = {}
    
    for idx, url in enumerate(enrich_urls):
        result = fetch_enrichment_data(url)
        enrichment_results[f'source_{idx}'] = {
            'url': url,
            'status': result['status'],
            'data': result['data']
        }
        
        # Add individual enrichment response headers
        # Base64 encode to ensure header-safe values
        encoded_data = base64_encode_safe(json.dumps(result['data']))
        header_name = f'x-enriched-data-{idx}'
        request['headers'][header_name] = [{
            'key': f'X-Enriched-Data-{idx}',
            'value': encoded_data
        }]
        
        # Add status header for each enrichment
        status_header_name = f'x-enriched-status-{idx}'
        request['headers'][status_header_name] = [{
            'key': f'X-Enriched-Status-{idx}',
            'value': str(result['status'])
        }]
    
    # Add a combined enrichment summary header
    summary = {
        'total_sources': len(enrich_urls),
        'successful': sum(1 for r in enrichment_results.values() if r['status'] == 200),
        'failed': sum(1 for r in enrichment_results.values() if r['status'] != 200)
    }
    encoded_summary = base64_encode_safe(json.dumps(summary))
    request['headers']['x-enrichment-summary'] = [{
        'key': 'X-Enrichment-Summary',
        'value': encoded_summary
    }]
    
    # Add combined enrichment payload (all results merged)
    combined_data = {}
    for key, result in enrichment_results.items():
        if result['status'] == 200 and isinstance(result['data'], dict):
            combined_data.update(result['data'])
        elif result['status'] == 200:
            combined_data[key] = result['data']
    
    if combined_data:
        encoded_combined = base64_encode_safe(json.dumps(combined_data))
        # Lambda@Edge has header size limits (~6,500 bytes for viewer request)
        # Truncate if necessary
        if len(encoded_combined) <= 6000:
            request['headers']['x-enriched-combined'] = [{
                'key': 'X-Enriched-Combined',
                'value': encoded_combined
            }]
    
    # Remove the original enrichment URL headers to avoid leaking internal URLs to origin
    cleanup_enrichment_headers(request['headers'])
    
    return request


def fetch_enrichment_data(url, timeout=2):
    """
    Fetch data from the given URL with a short timeout suitable for edge execution.
    
    Args:
        url: The URL to fetch data from
        timeout: Request timeout in seconds (keep low for Lambda@Edge)
    
    Returns:
        dict with 'status' and 'data' keys
    """
    # Validate URL scheme - only allow http and https
    if not url.startswith(('http://', 'https://')):
        return {
            'status': 400,
            'data': {'error': 'Invalid URL scheme. Only http and https are allowed.'}
        }
    
    # Basic SSRF protection - block private/internal IPs
    if is_private_url(url):
        return {
            'status': 403,
            'data': {'error': 'Requests to private/internal addresses are not allowed.'}
        }
    
    try:
        req = urllib.request.Request(
            url,
            headers={
                'User-Agent': 'LambdaEdge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
            },
            method='GET'
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            status_code = response.getcode()
            content_type = response.headers.get('Content-Type', '')
            raw_data = response.read().decode('utf-8', errors='replace')
            
            # Try to parse as JSON
            if 'json' in content_type or raw_data.strip().startswith(('{', '[')):
                try:
                    parsed_data = json.loads(raw_data)
                    return {
                        'status': status_code,
                        'data': parsed_data
                    }
                except json.JSONDecodeError:
                    pass
            
            # Return as plain text if not JSON
            # Truncate large responses to stay within Lambda@Edge limits
            max_length = 4000
            if len(raw_data) > max_length:
                raw_data = raw_data[:max_length] + '...[truncated]'
            
            return {
                'status': status_code,
                'data': {'text': raw_data}
            }
    
    except urllib.error.HTTPError as e:
        return {
            'status': e.code,
            'data': {'error': f'HTTP error: {e.code} {e.reason}'}
        }
    except urllib.error.URLError as e:
        return {
            'status': 502,
            'data': {'error': f'URL error: {str(e.reason)}'}
        }
    except Exception as e:
        return {
            'status': 500,
            'data': {'error': f'Request failed: {str(e)}'}
        }


def is_private_url(url):
    """
    Basic SSRF protection: check if URL points to private/internal addresses.
    """
    from urllib.parse import urlparse
    
    try:
        parsed = urlparse(url)
        hostname = parsed.hostname or ''
        
        # Block localhost and common internal hostnames
        blocked_hosts = [
            'localhost',
            '127.0.0.1',
            '0.0.0.0',
            '::1',
            'metadata.google.internal',
        ]
        
        if hostname.lower() in blocked_hosts:
            return True
        
        # Block AWS metadata endpoint
        if hostname == '169.254.169.254':
            return True
        
        # Block link-local addresses
        if hostname.startswith('169.254.'):
            return True
        
        # Block common private IP ranges
        private_prefixes = [
            '10.',
            '172.16.', '172.17.', '172.18.', '172.19.',
            '172.20.', '172.21.', '172.22.', '172.23.',
            '172.24.', '172.25.', '172.26.', '172.27.',
            '172.28.', '172.29.', '172.30.', '172.31.',
            '192.168.',
        ]
        
        for prefix in private_prefixes:
            if hostname.startswith(prefix):
                return True
        
        return False
    
    except Exception:
        # If we can't parse the URL, block it for safety
        return True


def base64_encode_safe(data_string):
    """
    Base64 encode a string for safe inclusion in HTTP headers.
    """
    return base64.b64encode(data_string.encode('utf-8')).decode('ascii')


def cleanup_enrichment_headers(headers):
    """
    Remove enrichment URL headers from the request so they are not
    forwarded to the origin server.
    """
    keys_to_remove = []
    
    for key in headers:
        if key.startswith('x-enrich-url'):
            keys_to_remove.append(key)
    
    for key in keys_to_remove:
        del headers[key]